def seed_db():
    db = SessionLocal()
    try:
        existing = {w.name for w in db.query(Worker).all()}
        added = 0
        for w in SEED:
            if w["name"] not in existing:
                wc = dict(w)
                tags = json.dumps(wc.pop("tags", []))
                worker = Worker(**wc, tags=tags)
                db.add(worker)
                added += 1
        db.commit()
        total = db.query(Worker).count()
        print(f"Snay3i.ma DB: added {added} workers, total {total} traders!")
    finally:
        db.close()

# seed_db()  # disabled: was re-adding 775 synthetic profiles on every restart

def serialize(w):
    return WorkerOut(id=w.id, name=w.name, service=w.service, city=w.city,
        rating=w.rating, reviews=w.reviews, verified=w.verified,
        bio=w.bio, tags=json.loads(w.tags) if w.tags else [],
        phone=w.phone or "", whatsapp=w.whatsapp or "",
        address=w.address or "", years_exp=w.years_exp or 1)

